{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting how shipments are created, routed, delivered, invoiced, and tracked. The change implies new business capabilities such as split deliveries, gift shipments to multiple parties, or consolidated shipments with multiple drop-off points.",
    "bounded_context": "Shipment Management / Order Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from an origin to one or more recipients. The aggregate root that owns the delivery lifecycle." },
      { "term": "Recipient", "definition": "A party receiving part or all of a shipment's contents. Identified by name, address, phone number, and delivery preferences. Formerly embedded in Shipment; now a first-class entity within the Shipment aggregate." },
      { "term": "Delivery Preference", "definition": "Recipient-level instructions governing how and when delivery should occur (e.g., safe place, signature required, time window, contactless)." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a shipment. For backward compatibility, legacy shipments have exactly one primary recipient." },
      { "term": "Drop-off Point", "definition": "A distinct delivery location derived from a recipient's address. Multi-recipient shipments may have multiple drop-off points, which affects routing." },
      { "term": "Delivery Attempt", "definition": "A courier's effort to deliver to a specific recipient. In a multi-recipient model, each recipient may have independent delivery attempts and statuses." },
      { "term": "Shipment Status", "definition": "The aggregate lifecycle state of a shipment. With multiple recipients, this must now be derived from the individual recipient delivery statuses — the shipment is only 'delivered' when ALL recipients have received their items." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no delivery destination. It is logically corrupt — there is nowhere to deliver, no route to plan, no notification to send. This is a data integrity constraint, not a policy choice.",
      "testable_assertion": "Creating or updating a Shipment with an empty recipients list must be rejected at the domain level."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These three fields are the minimum required to attempt delivery (address for routing, name for identification, phone for contact on failed delivery). Without any one of them, the courier cannot complete the delivery workflow.",
      "testable_assertion": "A Recipient missing name, address, or phone number must be rejected at creation time."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment may have independent delivery preferences that override any shipment-level defaults.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are business policy — the set of available preferences, their defaults, and override rules can change with product decisions.",
      "testable_assertion": "When Recipient A has preference 'signature required' and Recipient B has 'contactless', each delivery attempt must respect the individual recipient's preference, not a shipment-wide setting."
    },
    {
      "id": "BR-4",
      "rule": "Shipment-level status must be derived from the delivery status of ALL recipients. A shipment is 'delivered' only when every recipient has received their items.",
      "invariant": true,
      "invariant_justification": "If the shipment is marked 'delivered' while one recipient has not received their items, the system state is inconsistent with physical reality. This is a state integrity constraint — reporting a shipment as complete when it is not corrupts downstream billing, SLA tracking, and customer communication.",
      "testable_assertion": "A Shipment with 3 recipients where 2 are delivered and 1 is pending must have status 'partially_delivered' or 'in_progress', never 'delivered'."
    },
    {
      "id": "BR-5",
      "rule": "Legacy shipments (pre-migration) must be representable in the new model without data loss or semantic change. A single-recipient shipment is a multi-recipient shipment with exactly one recipient.",
      "invariant": true,
      "invariant_justification": "2 million existing shipments must remain queryable, reportable, and consistent. If the migration alters semantics (e.g., loses delivery preferences, changes status derivation), historical data is corrupted.",
      "testable_assertion": "After migration, every legacy shipment must have exactly one Recipient with the same name, address, and phone as the original embedded data. Querying a legacy shipment must return identical business data as before migration."
    },
    {
      "id": "BR-6",
      "rule": "Recipient ordering within a Shipment must be deterministic and represent the planned delivery sequence.",
      "invariant": false,
      "invariant_justification": "Delivery sequence is a routing optimization concern and may be reordered by dispatch algorithms. The ordering convention is a policy, not a hard constraint.",
      "testable_assertion": "Recipients must maintain a stable sequence/position attribute. The delivery route planner must respect this ordering unless overridden by dispatch."
    },
    {
      "id": "BR-7",
      "rule": "External partner API contracts must continue to function for single-recipient shipments without breaking changes. Multi-recipient data must be opt-in for partners.",
      "invariant": false,
      "invariant_justification": "API versioning and partner migration timelines are business policy decisions, not physical constraints. However, breaking partner integrations has severe operational consequences.",
      "testable_assertion": "Calling the existing partner API endpoint for a single-recipient shipment must return the same payload schema as before the model change. Multi-recipient shipments must either be excluded from the legacy endpoint or projected to the primary recipient only."
    },
    {
      "id": "BR-8",
      "rule": "A Recipient cannot appear more than once in the same Shipment (uniqueness by address + name combination).",
      "invariant": true,
      "invariant_justification": "Duplicate recipients on the same shipment indicate a data entry error and would cause double-delivery, double-billing, and confused couriers. This is a data consistency constraint.",
      "testable_assertion": "Adding a Recipient with the same name and address as an existing Recipient on the same Shipment must be rejected."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "the creator specifies three Recipients with distinct addresses and delivery preferences",
      "then": "the Shipment is created with all three Recipients, each retaining their individual preferences, and Shipment status is 'pending'"
    },
    {
      "id": "AC-2",
      "given": "A Shipment has three Recipients",
      "when": "two Recipients have been successfully delivered and one is still pending",
      "then": "the Shipment status is 'partially_delivered' (not 'delivered'), and tracking reflects per-recipient status"
    },
    {
      "id": "AC-3",
      "given": "A legacy single-recipient Shipment exists in production",
      "when": "the system is migrated to the multi-recipient model",
      "then": "the Shipment has exactly one Recipient with identical name, address, and phone. All existing queries, reports, and API responses return equivalent data."
    },
    {
      "id": "AC-4",
      "given": "An external partner integration receives shipment data via the current API format",
      "when": "a single-recipient shipment is sent to the partner",
      "then": "the partner receives the same payload schema as before — no breaking change"
    },
    {
      "id": "AC-5",
      "given": "An external partner integration receives shipment data via the current API format",
      "when": "a multi-recipient shipment is sent to the partner",
      "then": "the system either projects only the primary recipient into the legacy format OR excludes the shipment from the legacy endpoint, with clear documentation of the behavior"
    },
    {
      "id": "AC-6",
      "given": "A Shipment creation request is submitted",
      "when": "the recipients list is empty",
      "then": "the request is rejected with a validation error — the shipment is not created"
    },
    {
      "id": "AC-7",
      "given": "A Shipment with two Recipients",
      "when": "a third Recipient is added with the same name and address as an existing Recipient",
      "then": "the addition is rejected as a duplicate"
    },
    {
      "id": "AC-8",
      "given": "A Shipment with multiple Recipients, each having different delivery preferences",
      "when": "the courier attempts delivery for each Recipient",
      "then": "the courier app displays the correct delivery preference per Recipient, not a shipment-level default"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multi-recipient shipment where all recipients share the same address but have different delivery preferences",
      "expected_behavior": "Each recipient is treated independently — different preferences are honored even at the same address. The system must not de-duplicate recipients by address alone; name + address is the uniqueness key."
    },
    {
      "scenario": "One recipient on a multi-recipient shipment refuses delivery",
      "expected_behavior": "The refused recipient's status becomes 'refused'. The shipment remains 'in_progress' for remaining recipients. Return/re-attempt logic applies only to the refused recipient's portion."
    },
    {
      "scenario": "Partner API receives a multi-recipient shipment but only supports single-recipient format",
      "expected_behavior": "The integration layer must project the shipment to the primary recipient or fan out into N partner-side payloads. This decision must be explicit and configurable per partner — silent data loss (dropping recipients) is unacceptable."
    },
    {
      "scenario": "Migration of a legacy shipment that has already been delivered",
      "expected_behavior": "The migrated shipment must retain its 'delivered' status. The single recipient must show as delivered. No status recalculation should change historical outcomes."
    },
    {
      "scenario": "Shipment with N recipients where the maximum recipient limit is reached",
      "expected_behavior": "The system must enforce a configurable maximum recipients-per-shipment limit. Without a cap, routing algorithms may degrade, courier workload becomes unbounded, and UX breaks. The limit is a business policy (not invariant) and should be set by operations."
    },
    {
      "scenario": "Partial cancellation — one recipient is removed from a multi-recipient shipment after dispatch",
      "expected_behavior": "The remaining recipients' deliveries continue. The removed recipient's items follow the return/cancellation flow. The shipment is never left with zero recipients — if the last recipient is cancelled, the entire shipment is cancelled."
    },
    {
      "scenario": "Billing and invoicing for multi-recipient shipments",
      "expected_behavior": "Pricing model must account for multiple drop-off points. A shipment to 3 addresses is not the same cost as a shipment to 1 address. The billing system must be updated or the change will cause revenue leakage."
    },
    {
      "scenario": "Notifications (SMS/email) for multi-recipient shipments",
      "expected_behavior": "Each recipient receives their own delivery notifications based on their contact info and delivery status — not a single notification to the sender only."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient shipments require a new pricing model (per-drop-off surcharges or tiered pricing). Without this, revenue leakage occurs on every multi-recipient shipment. Migration of 2M records has infrastructure cost. Partner API changes may require renegotiation of SLAs and contracts.",
    "operational": "HIGH. Route optimization must handle multiple drop-off points per shipment. Courier workload estimation changes. Dispatch algorithms need updating. Warehouse pick-and-pack may need to segregate items by recipient within a single shipment. Support teams need training on new shipment structure.",
    "user": "MEDIUM-HIGH. Customers gain a valuable capability (send to multiple people in one shipment). Couriers face increased complexity per shipment. The courier app must clearly present per-recipient instructions or delivery errors will spike.",
    "risk": "HIGH. This is a breaking change to the core domain model. Risks include: (1) data migration failure on 2M records causing production outage, (2) partner API breakage causing integration failures, (3) status derivation bugs causing incorrect SLA reporting, (4) billing model mismatch causing revenue loss, (5) downstream systems (analytics, reporting, compliance) that assume 1:1 Shipment:Recipient breaking silently.",
    "stakeholders_affected": [
      { "group": "Customers/Senders", "impact": "New capability to send to multiple recipients. UX must be intuitive or adoption will be low." },
      { "group": "Recipients", "impact": "Now receive independent tracking and notifications. Delivery preferences are respected individually." },
      { "group": "Couriers", "impact": "Increased complexity per shipment. Must handle multiple drop-offs, multiple delivery preferences, partial completion states. Training required." },
      { "group": "External Partners", "impact": "API contract change. Partners on legacy integration will break unless backward compatibility is maintained. Migration timeline and communication required." },
      { "group": "Operations/Dispatch", "impact": "Route planning algorithms must be updated. SLA tracking must account for per-recipient delivery. Dashboard and reporting changes needed." },
      { "group": "Finance/Billing", "impact": "Pricing model must evolve to account for multi-drop shipments. Invoicing must itemize per recipient or per drop-off." },
      { "group": "Customer Support", "impact": "Must handle new query types: 'one of my recipients got their delivery but another didn't.' Tools and training needed." },
      { "group": "Data/Analytics", "impact": "All reports assuming 1:1 Shipment:Recipient will produce incorrect results. ETL pipelines, dashboards, and KPIs need updating." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes the model change at a high level but leaves critical business decisions unresolved: How should shipment status be derived from recipient statuses? What is the pricing model? How should partner APIs handle multi-recipient data? What is the maximum recipients per shipment? How are items allocated across recipients? These gaps make it impossible to define complete, unambiguous acceptance criteria. The 2M record migration and partner API backward compatibility add significant risk that requires more specificity.",
    "high_confidence_areas": [
      "The 1:N relationship between Shipment and Recipient is the correct model evolution",
      "At-least-one-recipient invariant is non-negotiable",
      "Legacy data must be preserved without semantic change",
      "Partner API backward compatibility is required"
    ],
    "low_confidence_areas": [
      "Shipment status derivation rules for partial delivery states — spec does not define intermediate statuses",
      "Pricing model for multi-recipient shipments — not addressed",
      "How items within a shipment are allocated to specific recipients — not addressed",
      "Partner API strategy: primary-recipient projection vs. fan-out vs. new versioned endpoint",
      "Whether 'delivery preferences' is a closed or open set, and what preferences are supported"
    ],
    "assumptions": [
      "The existing Recipient data (name, address, phone) is currently embedded in the Shipment entity, not a separate table",
      "External partner APIs are synchronous integrations that push shipment data outbound",
      "The product team intends this for scenarios like gift-to-multiple or consolidated multi-drop, not for splitting a single package into sub-packages",
      "Delivery preferences are Recipient-scoped, not item-scoped"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'delivery preferences' without defining what preferences exist, their schema, or their validation rules. This is the core differentiator of the new model and cannot be left undefined — it affects the Recipient entity design, courier app UI, and operational workflows.",
      "affected_stakeholders": ["Product Team", "Couriers", "Recipients", "Engineering"],
      "options": [
        "A: Define a closed enum of preferences (signature_required, contactless, safe_place, time_window) now",
        "B: Make preferences a flexible key-value store extensible by product",
        "C: Start with a minimal set and evolve via feature flags"
      ],
      "recommendation": "Option C — ship with a minimal, well-defined set (signature_required, contactless, safe_place) and extend later. Avoids over-engineering while unblocking implementation."
    },
    {
      "type": "ambiguity",
      "description": "Shipment status derivation for multi-recipient scenarios is undefined. When 2 of 3 recipients are delivered, what is the shipment status? The spec must define the full state machine including intermediate states like 'partially_delivered'.",
      "affected_stakeholders": ["Operations/Dispatch", "Customer Support", "Data/Analytics", "External Partners"],
      "options": [
        "A: Introduce 'partially_delivered' as a new shipment status",
        "B: Keep shipment status as 'in_transit' until all recipients are delivered",
        "C: Deprecate shipment-level status entirely and move to per-recipient statuses only"
      ],
      "recommendation": "Option A — 'partially_delivered' is the most domain-accurate representation and gives operations and customers clear visibility into progress."
    },
    {
      "type": "missing_context",
      "description": "No guidance on how items within a shipment are allocated to recipients. Can a shipment contain 5 items where 3 go to Recipient A and 2 go to Recipient B? Or does each recipient get the full shipment contents? This fundamentally changes the domain model — it's the difference between a multi-drop shipment and a multi-copy shipment.",
      "affected_stakeholders": ["Product Team", "Warehouse Operations", "Couriers", "Finance/Billing"],
      "options": [
        "A: Each recipient receives the full shipment contents (multi-copy model — e.g., promotional materials)",
        "B: Items are explicitly allocated to recipients (multi-drop model — e.g., different orders consolidated)",
        "C: Support both models with a shipment-level flag"
      ],
      "recommendation": "Escalate to product team — this is the single most important design decision and it cannot be assumed. It changes warehouse operations, courier workflows, and billing."
    },
    {
      "type": "ambiguity",
      "description": "Partner API backward compatibility strategy is unspecified. With 2M existing shipments flowing through partner APIs, the migration path must be explicit. Options range from API versioning to projection layers to partner-by-partner migration timelines.",
      "affected_stakeholders": ["External Partners", "Engineering", "Business Development"],
      "options": [
        "A: Version the API (v1 returns single-recipient, v2 returns multi-recipient)",
        "B: Add recipients array to existing API with backward-compatible default (single element = same as before)",
        "C: Maintain legacy endpoint indefinitely, add new endpoint for multi-recipient"
      ],
      "recommendation": "Option B — additive change with backward compatibility. The existing 'recipient' field becomes syntactic sugar for 'recipients[0]'. New 'recipients' array is added. Partners can migrate at their own pace."
    }
  ],

  "rejection_reasons": []
}

